"import { clsx, type ClassValue } from 'clsx'
import { twMerge } from 'tailwind-merge'

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}
"

"import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cn } from "@/lib/utils"

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  asChild?: boolean
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost'
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, asChild = false, variant = 'primary', ...props }, ref) => {
    const Comp = asChild ? Slot : "button"
    return (
      <Comp
        className={cn(
          "tap inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-full text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 px-6 py-3",
          variant === 'primary' && "bg-primary text-primary-foreground shadow hover:opacity-90",
          variant === 'secondary' && "bg-secondary text-secondary-foreground hover:bg-secondary/80",
          variant === 'outline' && "border border-border bg-background text-foreground hover:bg-secondary",
          variant === 'ghost' && "text-foreground hover:bg-secondary",
          className
        )}
        ref={ref}
        {...props}
      />
    )
  }
)
Button.displayName = "Button"

export { Button }
"

"import React from 'react'
import { Link, useLocation } from 'react-router-dom'
import { Home, Radio, Award, Compass } from 'lucide-react'

export function BottomNavBar() {
  const location = useLocation()

  const tabs = [
    { label: '루틴', path: '/', icon: Home },
    { label: 'G-PAN', path: '/search', icon: Radio },
    { label: '로드보더', path: '/community', icon: Award },
    { label: '오토파일럿', path: '/autopilot', icon: Compass },
  ]

  return (
    <div className="fixed bottom-0 left-0 right-0 z-50 border-t border-border/60 bg-background/90 py-2 backdrop-blur-md md:hidden">
      <div className="mx-auto flex max-w-md justify-around px-2">
        {tabs.map((tab) => {
          const isActive = location.pathname === tab.path
          const Icon = tab.icon
          return (
            <Link
              key={tab.path}
              to={tab.path}
              className={`tap flex flex-col items-center gap-1 px-3 py-1.5 ${isActive ? 'text-primary' : 'text-muted-foreground'}`}
            >
              <Icon className="h-5 w-5" strokeWidth={isActive ? 2.2 : 1.8} />
              <span className="text-[10px] font-medium tracking-tight">
                {tab.label}
              </span>
            </Link>
          )
        })}
      </div>
    </div>
  )
}
