      </h1>

      {/* 테마 테스트용 버튼 셋 (추후 자동화) */}
      <div className="flex gap-2 bg-card p-1 rounded-full border border-border">
        <button 
          onClick={() => setTheme('day')} 
          className={`tap p-2 rounded-full ${theme === 'day' ? 'bg-primary text-primary-foreground' : 'text-foreground'}`}
        >
          <Sun size={18} />
        </button>
        <button 
          onClick={() => setTheme('sunset')} 
          className={`tap p-2 rounded-full ${theme === 'sunset' ? 'bg-primary text-primary-foreground' : 'text-foreground'}`}
        >
          <Sunset size={18} />
        </button>
        <button 
