15:     const cipher = crypto.createCipheriv(ALGORITHM, SECRET_KEY, iv);
16:     let encrypted = cipher.update(text, 'utf8', 'hex');
17:     encrypted += cipher.final('hex');
18:     const authTag = cipher.getAuthTag().toString('hex');
19:     // Combine iv, authTag, and ciphertext using colons
20:     return `${iv.toString('hex')}:${authTag}:${encrypted}`;
21:   } catch (err) {
22:     console.error('[Crypto] Encryption failed, returning plain text:', err);
23:     return text;
